SELECT s.stadium_name, s.performance_rating
FROM stadiums s
WHERE s.performance_rating = (
    SELECT MAX(performance_rating)
    FROM stadiums
);

SELECT s.stadium_name
FROM stadiums s
WHERE s.performance_rating = (
    SELECT MAX(performance_rating)
    FROM stadiums
);

SELECT stadium_name
FROM stadiums
WHERE performance_rating = (
    SELECT MAX(performance_rating)
    FROM stadiums
);
